async def _ensure_workflow_context():
    context_manager = GriptapeNodes.ContextManager()
    if not context_manager.has_current_flow():
        top_level_flow_request = GetTopLevelFlowRequest()
        top_level_flow_result = await GriptapeNodes.ahandle_request(top_level_flow_request)
        if isinstance(top_level_flow_result, GetTopLevelFlowResultSuccess) and top_level_flow_result.flow_name is not None:
            flow_manager = GriptapeNodes.FlowManager()
            flow_obj = flow_manager.get_flow_by_name(top_level_flow_result.flow_name)
            context_manager.push_flow(flow_obj)

def execute_workflow(input: dict, storage_backend: str='local', project_file_path: str | None=None, workflow_executor: WorkflowExecutor | None=None, pickle_control_flow_result: bool=False) -> dict | None:
    return asyncio.run(aexecute_workflow(input=input, storage_backend=storage_backend, project_file_path=project_file_path, workflow_executor=workflow_executor, pickle_control_flow_result=pickle_control_flow_result))

async def aexecute_workflow(input: dict, storage_backend: str='local', project_file_path: str | None=None, workflow_executor: WorkflowExecutor | None=None, pickle_control_flow_result: bool=False) -> dict | None:
    await build_workflow()
    await _ensure_workflow_context()
    storage_backend_enum = StorageBackend(storage_backend)
    project_file_path_resolved = Path(project_file_path) if project_file_path is not None else None
    workflow_executor = workflow_executor or LocalWorkflowExecutor(storage_backend=storage_backend_enum, project_file_path=project_file_path_resolved, skip_library_loading=True, workflows_to_register=[__file__])
    async with workflow_executor as executor:
        await executor.arun(flow_input=input, pickle_control_flow_result=pickle_control_flow_result)
    return executor.output

if __name__ == '__main__':
    logging.basicConfig(level=logging.INFO)
    parser = argparse.ArgumentParser()
    parser.add_argument('--storage-backend', choices=['local', 'gtc'], default='local', help="Storage backend to use: 'local' for local filesystem or 'gtc' for Griptape Cloud")
    parser.add_argument('--project-file-path', default=None, help='Path to a project file to load for the workflow execution')
    parser.add_argument('--json-input', default=None, help='JSON string containing parameter values. Takes precedence over individual parameter arguments if provided.')
    parser.add_argument('--exec_out', default=None, help='Connection to the next node in the execution chain')
    parser.add_argument('--input0', default=None, help='Enter text/string for input0.')
    parser.add_argument('--input1', default=None, help='Enter text/string for input1.')
    parser.add_argument('--output_path', default=None, help='Enter text/string for output_path.')
    parser.add_argument('--fill_content', default=None, help='New parameter')
    parser.add_argument('--model', default=None, help='New parameter')
    parser.add_argument('--local', default=None, help='Enter boolean (true/false) for local.')
    parser.add_argument('--guidance_scale', default=None, help='New parameter')
    parser.add_argument('--num_inference_steps', default=None, help='New parameter')
    parser.add_argument('--seed', default=None, help='New parameter')
    args = parser.parse_args()
    flow_input = {}
    if args.json_input is not None:
        flow_input = json.loads(args.json_input)
    if args.json_input is None:
        if 'Start Flow' not in flow_input:
            flow_input['Start Flow'] = {}
        if args.exec_out is not None:
            flow_input['Start Flow']['exec_out'] = args.exec_out
        if args.input0 is not None:
            flow_input['Start Flow']['input0'] = args.input0
        if args.input1 is not None:
            flow_input['Start Flow']['input1'] = args.input1
        if args.output_path is not None:
            flow_input['Start Flow']['output_path'] = args.output_path
        if args.fill_content is not None:
            flow_input['Start Flow']['Fill_Content'] = args.fill_content
        if args.model is not None:
            flow_input['Start Flow']['model'] = args.model
        if args.local is not None:
            flow_input['Start Flow']['local'] = args.local
        if args.guidance_scale is not None:
            flow_input['Start Flow']['guidance_scale'] = args.guidance_scale
        if args.num_inference_steps is not None:
            flow_input['Start Flow']['num_inference_steps'] = args.num_inference_steps
        if args.seed is not None:
            flow_input['Start Flow']['seed'] = args.seed
    workflow_output = execute_workflow(input=flow_input, storage_backend=args.storage_backend, project_file_path=args.project_file_path)
    print(workflow_output)
